# OEIS sequence: A344675

from sympy import integer_nthroot
def A344675(n):
    c, j, n2 = 0, 1, n**3
    while j <= n:
        k = n2//j**3
        m = integer_nthroot(n2//k,3)[0]
        c += k*(m-j+1)
        j = m+1
    return c # _Chai Wah Wu_, May 21 2026

